#!/usr/bin/env python3
"""Compute formal compliance metrics from audit source documents.

Usage: compute_compliance_metrics.py <workspace-root>
Outputs a single-line JSON object to stdout.
"""

from __future__ import annotations

import json
import re
import sys
from pathlib import Path


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def count_findings(findings: str) -> int:
    return len(re.findall(r"^###\s+Finding\s+F\d+:", findings, re.M))


def nurses_affected(findings: str) -> int:
    m = re.search(r"affected\s+\*\*(\d+)\s+of\s+\d+\s+full-time\*\*", findings, re.I)
    if not m:
        raise ValueError("Could not extract affected nurse count from F2")
    return int(m.group(1))


def months_of_falsification(findings: str) -> int:
    # F1 documents the same systematic falsification period later scoped in F2:
    # "for at least **4 months**".
    m = re.search(r"at least\s+\*\*(\d+)\s+months\*\*", findings, re.I)
    if not m:
        m = re.search(r"at least\s+(\d+)\s+months", findings, re.I)
    if not m:
        raise ValueError("Could not extract months of falsification")
    return int(m.group(1))


def mandatory_reporting_hours(findings: str) -> int:
    m = re.search(r"within\s+\*\*(\d+)\s+hours\*\*", findings, re.I)
    if not m:
        m = re.search(r"within\s+(\d+)\s+hours", findings, re.I)
    if not m:
        raise ValueError("Could not extract mandatory reporting hours")
    return int(m.group(1))


def audit_violation_counts(audit: str) -> tuple[int, int]:
    above_48 = above_60 = None
    m48 = re.search(r"Nurses exceeding 48h/week\s*\|\s*0\s*\|\s*(\d+)\s+of\s+\d+", audit, re.I)
    if m48:
        above_48 = int(m48.group(1))
    m60 = re.search(r"Nurses exceeding 60h/week\s*\|\s*0\s*\|\s*(\d+)\s+of\s+\d+", audit, re.I)
    if m60:
        above_60 = int(m60.group(1))

    if above_48 is None or above_60 is None:
        manual_hours = []
        for line in audit.splitlines():
            if line.startswith("| RN-"):
                cells = [c.strip().strip("*") for c in line.strip().strip("|").split("|")]
                if len(cells) >= 4:
                    try:
                        manual_hours.append(float(cells[3]))
                    except ValueError:
                        pass
        if above_48 is None:
            above_48 = sum(1 for h in manual_hours if h > 48.0)
        if above_60 is None:
            above_60 = sum(1 for h in manual_hours if h > 60.0)

    return above_48, above_60


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Usage: compute_compliance_metrics.py <workspace-root>")

    root = Path(sys.argv[1])
    audit = read_text(root / "overtime_audit_report.md")
    # Read badge file as required input; F2's nurse count is corroborated there.
    read_text(root / "badge_access_analysis.md")
    findings = read_text(root / "caresched_audit_findings.md")

    above_48, above_60 = audit_violation_counts(audit)
    result = {
        "finding_count": count_findings(findings),
        "nurses_affected": nurses_affected(findings),
        "months_of_falsification": months_of_falsification(findings),
        "mandatory_reporting_hours": mandatory_reporting_hours(findings),
        "violations_above_48h": above_48,
        "violations_above_60h": above_60,
    }
    print(json.dumps(result, separators=(",", ":")))


if __name__ == "__main__":
    main()

